//! Completion Handler: textDocument/completion
//! Generated by ggen lsp-max pack

use lsp_max::jsonrpc::Result;
use lsp_types_max::*;

use crate::hover::schema_key_for_uri;
use crate::schema::build_schema;

/// Provide context-aware completions for Claude Code config files.
pub async fn completion(params: CompletionParams) -> Result<Option<CompletionResponse>> {
    let uri = params
        .text_document_position
        .text_document
        .uri
        .to_string();
    let schema_key = schema_key_for_uri(&uri);
    if schema_key.is_empty() {
        return Ok(None);
    }
    let schema = build_schema();
    if let Some(node) = schema.types.get(schema_key) {
        let items: Vec<CompletionItem> = node.fields.iter().map(|(name, ft)| {
            let opt = if ft.is_optional { "optional" } else { "required" };
            CompletionItem {
                label: name.clone(),
                kind: Some(CompletionItemKind::FIELD),
                detail: Some(format!("{} — {opt} ({})", ft.name, ft.stability)),
                ..Default::default()
            }
        }).collect();
        return Ok(Some(CompletionResponse::List(CompletionList {
            is_incomplete: false,
            items,
            ..Default::default()
        })));
    }
    Ok(None)
}

/// Resolve additional details for a completion item.
pub async fn completion_item_resolve(item: CompletionItem) -> Result<CompletionItem> {
    Ok(item)
}
